-- =====================================================================
-- 1. DATASET CREATION (DATA PRODUCT BOUNDARY)
-- =====================================================================
-- One dataset representing one Core Customer Business Object
CREATE SCHEMA IF NOT EXISTS `customer_v1`
OPTIONS(
  location="europe-west1",
  description="Customer Core Master Data Product containing verified profiles and regulatory risk classifications for the insurance and financial lines of business."
);

-- =====================================================================
-- 2. TABLE CREATION WITH CONSTRAINTS AND METADATA
-- =====================================================================

-- Table 1: Master Customer Profile
CREATE TABLE IF NOT EXISTS `customer_v1.customers` (
  customer_id STRING OPTIONS(description="Globally unique identifier for the customer (CUST-YYYY-XXXX format)"),
  first_name STRING OPTIONS(description="The customer's legal first name"),
  last_name STRING OPTIONS(description="The customer's legal last name"),
  email STRING OPTIONS(description="Primary contact email address, sanitized and verified"),
  phone_number STRING OPTIONS(description="Primary contact phone number in E.164 international format"),
  date_of_birth DATE OPTIONS(description="Customer's date of birth used for product eligibility and underwriting calculations"),
  kyc_status STRING OPTIONS(description="Know Your Customer (KYC) compliance verification status: PENDING, VERIFIED, REJECTED, SUSPENDED"),
  customer_segment STRING OPTIONS(description="Internal customer segmentation: RETAIL, MASS_AFFLUENT, HIGH_NET_WORTH, INSTITUTIONAL"),
  created_timestamp TIMESTAMP OPTIONS(description="UTC timestamp when the master record was first registered"),
  updated_timestamp TIMESTAMP OPTIONS(description="UTC timestamp of the last recorded update to the master profile"),
  PRIMARY KEY (customer_id) NOT ENFORCED
)
OPTIONS(
  description="Master registry of all active and legacy customers holding insurance policies or financial accounts."
);

-- Table 2: Financial Risk and Suitability Profile
CREATE TABLE IF NOT EXISTS `customer_v1.customer_risk_profiles` (
  risk_profile_id STRING OPTIONS(description="Unique identifier for the risk assessment instance"),
  customer_id STRING OPTIONS(description="Foreign key linking to the master customer profile"),
  risk_appetite STRING OPTIONS(description="Declared financial risk tolerance: CONSERVATIVE, MODERATE, AGGRESSIVE, SPECULATIVE"),
  aml_risk_rating STRING OPTIONS(description="Anti-Money Laundering (AML) risk tier: LOW, MEDIUM, HIGH"),
  suitability_score INT64 OPTIONS(description="Calculated financial product suitability score ranging from 1 to 100"),
  net_worth_estimated NUMERIC OPTIONS(description="Estimated customer net worth denominated in EUR, used for financial underwriting limits"),
  last_assessment_date DATE OPTIONS(description="Date of the most recent compliance and suitability assessment"),
  PRIMARY KEY (risk_profile_id) NOT ENFORCED,
  CONSTRAINT fk_customer FOREIGN KEY (customer_id) REFERENCES `customer_v1.customers`(customer_id) NOT ENFORCED
)
OPTIONS(
  description="Risk attributes and KYC-associated assessments required for financial compliance, profiling, and advisory underwriting."
);

